// mm/src/components/ui/PaymentDelivery.js
import React, { useMemo, useState } from 'react';
import { createCheckoutSession } from '../api/checkout';

const DEFAULT_PACKAGE_PRICES = {
  basic: 49,
  standard: 99,
  premium: 199,
};

export default function PaymentDelivery({
  packageId,
  packagePrices = DEFAULT_PACKAGE_PRICES,
  email,
  onEmailChange,
  checkoutPayload, // object OR function that returns object
  className = '',
  onRedirect, // optional override for redirect behavior
}) {
  const [isPaying, setIsPaying] = useState(false);
  const [error, setError] = useState('');

  const total = packagePrices?.[packageId] ?? 0;

  const canPay = useMemo(() => {
    const hasPkg = !!packageId;
    const hasEmail = (email || '').trim().length > 0;
    return hasPkg && hasEmail && total > 0 && !isPaying;
  }, [packageId, email, total, isPaying]);

  const handlePay = async () => {
    setError('');
    if (!canPay) return;

    setIsPaying(true);
    try {
      const payload =
        typeof checkoutPayload === 'function' ? checkoutPayload() : checkoutPayload;

      const finalPayload = {
        ...(payload || {}),
        packageId,
        email: (email || '').trim(),
      };

      const { url } = await createCheckoutSession(finalPayload);

      if (onRedirect) {
        onRedirect(url);
      } else {
        window.location.assign(url);
      }
    } catch (e) {
      console.error(e);
      setError(e?.message || 'Payment failed. Please try again.');
      setIsPaying(false);
    }
  };

  return (
    <div className={['border rounded-xl p-6 bg-white', className].join(' ')}>
      <div className="flex items-center gap-2">
        <div className="text-2xl font-semibold text-slate-900">Payment &amp; Delivery</div>
      </div>

      <div className="mt-6">
        <label className="block text-sm font-medium text-slate-700">
          Email Address for File Delivery <span className="text-red-500">*</span>
        </label>
        <input
          value={email || ''}
          onChange={(e) => onEmailChange?.(e.target.value)}
          placeholder="your.email@example.com"
          className="mt-2 w-full border rounded-md px-3 py-2"
        />
        <div className="mt-2 text-xs text-slate-500">
          Your formatted files will be delivered to this email address.
        </div>
      </div>

      <div className="mt-6 bg-slate-50 border rounded-lg p-4 text-sm text-slate-600">
        <strong className="text-slate-700">Secure Payment:</strong> All transactions are processed
        securely through Stripe. Your payment information is encrypted and never stored on our
        servers.
      </div>

      {error ? <div className="mt-4 text-sm text-red-600">{error}</div> : null}

      <button
        type="button"
        onClick={handlePay}
        disabled={!canPay}
        className={[
          'mt-6 w-full py-3 rounded-md font-semibold text-white transition flex items-center justify-center gap-2',
          canPay ? 'bg-blue-600 hover:bg-blue-700' : 'bg-slate-300 cursor-not-allowed',
        ].join(' ')}
      >
        {isPaying ? 'Redirecting…' : `Pay $${total}`}
      </button>
    </div>
  );
}
